VALUES
  ('judicial-57f41407-moex-00853', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於第三人撤銷訴訟之裁判，下列敘述何者正確？', '["原告起訴不合法者，法院得不經言詞辯論，逕以判決駁回其訴", "原告起訴依其所述事實顯無理由者，法院得不經言詞辯論，逕以判決駁回其訴", "原告起訴如無不合法或顯無理由之情形，法院應就原確定判決之全部範圍為辯論及裁判", "法院認第三人撤銷之訴為有理由者，均應將原確定判決全部撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00854', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '債務人對於支付命令未於法定期間內提出合法異議者，下列敘述何者正確？', '["支付命令與確定判決有同一之效力", "支付命令與訴訟上和解有同一之效力", "支付命令與訴訟上調解有同一之效力", "支付命令得為執行名義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00855', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於假扣押，下列敘述何者錯誤？', '["請求及假扣押之原因均應釋明", "請求及假扣押之原因均未釋明，債權人得以擔保代之", "請求及假扣押之原因雖經釋明，法院亦得命債權人供擔保後為假扣押", "夫或妻基於剩餘財產差額分配請求權聲明假扣押者，擔保金額不得高於請求金額10分之1"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00856', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '在某遊樂園之粉塵燃燒事件，造成400多位燒傷之受害人，若該等受害人擬向賠償義務人訴請民事損 害賠償，下列敘述何者正確？', '["全體被害人必須依團體訴訟方式始得為之", "得由其中選定一人或數人，為選定人及被選定人全體起訴", "被選定之人得更換或增減之，為求訴訟經濟，無須通知他造", "被選定人有為選定人為一切訴訟之權，不得限制之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00857', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於依家事事件法所作成之本案裁判及其執行名義，下列敘述何者錯誤？', '["法院命相對人給付扶養費時，關於給付方法，受聲請人聲明之拘束", "暫時處分之執行，原則上得不待當事人之聲請，由法院依職權為之", "法院命相對人給付贍養費而為分期給付之裁定者，得酌定逾期不履行時，喪失期限利益之範圍或條件", "債務人依執行名義應分期給付贍養費，而有一期未完全履行時，債權人就其餘履行期尚未屆至部分， 亦得聲請強制執行 乙、刑事訴訟法部分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00858', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '告訴人對於不起訴或緩起訴處分聲請再議，得於接受處分書後幾日內為之？', '["10日", "15日", "20日", "30日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00859', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於刑事訴訟之文書，下列敘述何者正確？', '["審判筆錄內引用附卷之文書者，其文書所記載之事項，僅供參考", "辯護人不必經審判長許可，得逕行於審判期日攜同速記到庭記錄", "審判期日之訴訟程序，專以審判筆錄為證", "裁判得由法官助理制作裁判書"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00860', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲遲誤上訴法定期間後，得因下列何項事由，於原因消滅後5日內，聲請回復原狀？', '["甲將上訴之事託於年邁耳聾之母親", "甲請教律師解釋判決內容", "甲罹患重病被醫院移入加護病房", "甲因請熟悉法律之朋友代撰上訴狀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00861', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '有關聲請法官迴避，下列敘述何者正確？', '["辯護人得隨時聲請法官迴避", "對於法官迴避的聲請，由其所屬法院管轄", "對於駁回法官迴避聲請的裁定，不得抗告", "審判期日，不得以言詞方式聲請法官迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00862', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '刑事訴訟法第268條規定法院不得就未經起訴之犯罪審判，乃屬控訴原則。控訴原則以三面訴訟為其 特色，下列何者不包含在三面關係中？', '["告訴人", "被告", "檢察官", "法官"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
